    yycur match {
      case CoolTokens.VAR() => yynext; yygoto = yystate18();
      case CoolTokens.OVERRIDE() => yynt = YYNTopt_override(yyrule64()); yygoto = 0
      case _ => yynt = YYNTopt_override(yyrule65()); yygoto = 0
    }
    while (yygoto == 0) {
      yynt match {
        case YYNTopt_override(yyarg1) => yygoto = yystate73(yyarg1);
        case YYNTfeature(yyarg1) => yygoto = yystate85(yyarg1);
        case _:YYNTerror => return 0;
      }
    }
    yygoto-1
  }

  private def yystate13(yyarg1: Features) : Int = {
    var yygoto : Int = 0;
    yycur match {
      case CoolTokens.VAR() => yynt = YYNTfeature_list(yyrule9(yyarg1)); yygoto = 1
      case CoolTokens.OVERRIDE() => yynt = YYNTfeature_list(yyrule9(yyarg1)); yygoto = 1
      case CoolTokens.YYCHAR('}') => yynt = YYNTfeature_list(yyarg1); yygoto = 2;
      case CoolTokens.YYCHAR('{') => yynt = YYNTfeature_list(yyrule10(yyarg1)); yygoto = 1
      case _ => yynt = YYNTfeature_list(yyrule9(yyarg1)); yygoto = 1
    }
    while (yygoto == 0) {
      yynt match {
        case _:YYNTfeature_list => return 0;
        case _:YYNTerror => return 0;
      }
    }
    yygoto-1
  }

  private def yystate12() : Int = {
    var yygoto : Int = 0;
    yycur match {
      case CoolTokens.YYCHAR('}') => yynt = YYNTfeature_list(yyrule8()); yygoto = 0
      case _ => yynt = YYNTfeature_list(yyrule8()); yygoto = 0
    }
    while (yygoto == 0) {
      yynt match {
        case YYNTfeature_list(yyarg1) => yygoto = yystate13(yyarg1);
        case _:YYNTerror => return 0;
      }
    }
    yygoto-1
  }

  private def yystate91(yyarg1: Formal) : Int = {
    var yygoto : Int = 0;
    yycur match {
      case CoolTokens.YYCHAR(',') => yynt = YYNTvar_formal(yyarg1); yygoto = 2;
      case CoolTokens.YYCHAR(')') => yynt = YYNTvar_formal(yyarg1); yygoto = 2;
      case _ => yynt = YYNTerror("syntax error");
    }
    while (yygoto == 0) {
      yynt match {
        case _:YYNTvar_formal => return 0;
        case _:YYNTerror => return 0;
      }
    }
    yygoto-1
  }

  private def yystate90() : Int = {
    var yygoto : Int = 0;
    yycur match {
      case CoolTokens.VAR() => yynt = YYNTvar_formal(yyrule19()); yygoto = 0
      case _ => yynt = YYNTerror("syntax error");
    }
    while (yygoto == 0) {
      yynt match {
        case YYNTvar_formal(yyarg1) => yygoto = yystate91(yyarg1);
        case _:YYNTerror => return 0;
      }
    }
    yygoto-1
  }

  private def yystate110(yyarg1: Expressions) : Int = {
    var yygoto : Int = 0;
    yycur match {
      case CoolTokens.YYCHAR(',') => yynt = YYNTexpr_list(yyrule56(yyarg1)); yygoto = 1
      case CoolTokens.YYCHAR(')') => yynt = YYNTexpr_list(yyarg1); yygoto = 2;
      case _ => yynt = YYNTerror("syntax error");
    }
    while (yygoto == 0) {
      yynt match {
        case _:YYNTexpr_list => return 0;
        case _:YYNTerror => return 0;
      }
    }
    yygoto-1
  }

  private def yystate109() : Int = {
    var yygoto : Int = 0;
    yycur match {
      case CoolTokens.SUPER() => yynt = YYNTexpr_list(yyrule55()); yygoto = 0
      case CoolTokens.THIS() => yynt = YYNTexpr_list(yyrule55()); yygoto = 0
      case CoolTokens.BOOL_LIT(_) => yynt = YYNTexpr_list(yyrule55()); yygoto = 0
      case CoolTokens.NEW() => yynt = YYNTexpr_list(yyrule55()); yygoto = 0
      case CoolTokens.IF() => yynt = YYNTexpr_list(yyrule55()); yygoto = 0
      case CoolTokens.YYCHAR('-') => yynt = YYNTexpr_list(yyrule55()); yygoto = 0
      case CoolTokens.YYCHAR('!') => yynt = YYNTexpr_list(yyrule55()); yygoto = 0
      case CoolTokens.NULL() => yynt = YYNTexpr_list(yyrule55()); yygoto = 0
      case CoolTokens.STR_LIT(_) => yynt = YYNTexpr_list(yyrule55()); yygoto = 0
      case CoolTokens.OBJECTID(_) => yynt = YYNTexpr_list(yyrule55()); yygoto = 0
      case CoolTokens.YYCHAR('(') => yynt = YYNTexpr_list(yyrule55()); yygoto = 0
      case CoolTokens.INT_LIT(_) => yynt = YYNTexpr_list(yyrule55()); yygoto = 0
      case CoolTokens.WHILE() => yynt = YYNTexpr_list(yyrule55()); yygoto = 0
      case CoolTokens.YYCHAR('{') => yynt = YYNTexpr_list(yyrule55()); yygoto = 0
      case _ => yynt = YYNTerror("syntax error");
    }
    while (yygoto == 0) {
      yynt match {
        case YYNTexpr_list(yyarg1) => yygoto = yystate110(yyarg1);
        case _:YYNTerror => return 0;
      }
    }
    yygoto-1
  }

  private def yystate3(yyarg1: Classes) : Int = {
    var yygoto : Int = 0;
    yycur match {
      case CoolTokens.YYEOF() => yynt = YYNTclass_list(yyarg1); yygoto = 2;
      case CoolTokens.CLASS() => yynt = YYNTclass_list(yyrule3(yyarg1)); yygoto = 1
      case _ => yynt = YYNTerror("syntax error");
    }
    while (yygoto == 0) {
      yynt match {
        case _:YYNTclass_list => return 0;
        case _:YYNTerror => return 0;
      }
    }
    yygoto-1
  }

  private def yystate2() : Int = {
    var yygoto : Int = 0;
    yycur match {
      case CoolTokens.CLASS() => yynt = YYNTclass_list(yyrule2()); yygoto = 0
      case _ => yynt = YYNTerror("syntax error");
    }
    while (yygoto == 0) {
      yynt match {
        case YYNTclass_list(yyarg1) => yygoto = yystate3(yyarg1);
        case _:YYNTerror => return 0;
      }
    }
    yygoto-1
  }

  private def yystate93(yyarg1: Formals) : Int = {
    var yygoto : Int = 0;
    yycur match {
      case CoolTokens.YYCHAR(',') => yynt = YYNTformals_one_or_more(yyrule23(yyarg1)); yygoto = 1
      case CoolTokens.YYCHAR(')') => yynt = YYNTformals_one_or_more(yyarg1); yygoto = 2;
      case _ => yynt = YYNTerror("syntax error");
    }
    while (yygoto == 0) {
      yynt match {
        case _:YYNTformals_one_or_more => return 0;
        case _:YYNTerror => return 0;
      }
    }
    yygoto-1
  }

  private def yystate92() : Int = {
    var yygoto : Int = 0;
    yycur match {
      case CoolTokens.OBJECTID(_) => yynt = YYNTformals_one_or_more(yyrule22()); yygoto = 0
      case _ => yynt = YYNTerror("syntax error");
    }
    while (yygoto == 0) {
      yynt match {
        case YYNTformals_one_or_more(yyarg1) => yygoto = yystate93(yyarg1);
        case _:YYNTerror => return 0;
      }
    }
    yygoto-1
  }

  private def yystate16(yyarg1: Expressions) : Int = {
    var yygoto : Int = 0;
    yycur match {
      case CoolTokens.LE() => yynt = YYNTactuals(yyarg1); yygoto = 2;
      case CoolTokens.YYCHAR(',') => yynt = YYNTactuals(yyarg1); yygoto = 2;
      case CoolTokens.YYCHAR('<') => yynt = YYNTactuals(yyarg1); yygoto = 2;
      case CoolTokens.MATCH() => yynt = YYNTactuals(yyarg1); yygoto = 2;
      case CoolTokens.YYCHAR(')') => yynt = YYNTactuals(yyarg1); yygoto = 2;
      case CoolTokens.YYCHAR('.') => yynt = YYNTactuals(yyarg1); yygoto = 2;
      case CoolTokens.ELSE() => yynt = YYNTactuals(yyarg1); yygoto = 2;
      case CoolTokens.YYCHAR('-') => yynt = YYNTactuals(yyarg1); yygoto = 2;
      case CoolTokens.YYCHAR('*') => yynt = YYNTactuals(yyarg1); yygoto = 2;
      case CoolTokens.YYCHAR(';') => yynt = YYNTactuals(yyarg1); yygoto = 2;
      case CoolTokens.CASE() => yynt = YYNTactuals(yyarg1); yygoto = 2;
      case CoolTokens.YYCHAR('+') => yynt = YYNTactuals(yyarg1); yygoto = 2;
      case CoolTokens.YYCHAR('}') => yynt = YYNTactuals(yyarg1); yygoto = 2;
      case CoolTokens.EQEQ() => yynt = YYNTactuals(yyarg1); yygoto = 2;
      case CoolTokens.YYCHAR('/') => yynt = YYNTactuals(yyarg1); yygoto = 2;
      case CoolTokens.YYCHAR('{') => yynt = YYNTactuals(yyarg1); yygoto = 2;
      case _ => yynt = YYNTerror("syntax error");
    }
    while (yygoto == 0) {
      yynt match {
        case _:YYNTactuals => return 0;
        case _:YYNTerror => return 0;
      }
    }
    yygoto-1
  }

  private def yystate14() : Int = {
    var yygoto : Int = 0;
    yycur match {
      case CoolTokens.YYCHAR('(') => yynext; yygoto = yystate15();
      case _ => yynt = YYNTerror("syntax error");
    }
    while (yygoto == 0) {
      yynt match {
        case YYNTactuals(yyarg1) => yygoto = yystate16(yyarg1);
        case _:YYNTerror => return 0;
      }
    }
    yygoto-1
  }

